// src/App.js
import React, { useState, useEffect, useRef } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Sample Cards ---
const bereshitCard = {
  name: "Bereshit",
  questions: [
    { question: "What day was Adam created?", answer: "The 6th day", points: 20 },
    { question: "Which day is described as 'very good'?", answer: "The 6th day", points: 20 },
    { question: "Name a story where addition becomes subtraction.", answer: "Adam added a prohibition; the serpent used this to fool Chava.", points: 20 },
  ],
};

const harHaBayitCard = {
  name: "Har HaBayit",
  questions: [
    { question: 'Which items were housed in the Kodesh ("holy") chamber?', answer: "The showbread table, menorah, and incense altar", points: 300 },
    { question: "Name an offering associated with the Omer or the Two Loaves.", answer: "Shtei Halechem (the Two Loaves) and the Omer offering are linked to Temple worship.", points: 600 },
  ],
};

const mazalCard = {
  name: "Mazal",
  text: "You had a dream of buried treasure in a far-off city... You dropped the shovel and ran home to discover the treasure buried under your own bed.",
  reward: 1000,
  rewardType: "money",
};

// --- Q&A Component ---
function CardQA({ card, onFinish }) {
  const [currentQ, setCurrentQ] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);
  const [accepted, setAccepted] = useState(Array(card.questions ? card.questions.length : 0).fill(false));
  const isMazal = card.name === "Mazal";

  useEffect(() => {
    setCurrentQ(0);
    setShowAnswer(false);
    setAccepted(Array(card.questions ? card.questions.length : 0).fill(false));
  }, [card]);

  const toggleAnswer = () => setShowAnswer((v) => !v);
  const acceptCorrect = () => setAccepted((prev) => { const copy = [...prev]; copy[currentQ] = true; return copy; });
  const prevQuestion = () => { setShowAnswer(false); setCurrentQ((i) => (i > 0 ? i - 1 : i)); };
  const nextQuestion = () => { setShowAnswer(false); setCurrentQ((i) => (i < (card.questions ? card.questions.length - 1 : 0) ? i + 1 : i)); };
  const totalPoints = accepted.reduce((sum, val, i) => (val ? sum + (card.questions[i].points || 0) : sum), 0);
  const allCorrect = accepted.length > 0 ? accepted.every((val) => val === true) : false;

  return (
    <div style={styles.qaOverlay}>
      <div style={styles.qaContainer}>
        <h2>{card.name} Card</h2>
        {isMazal ? (
          <>
            <p style={{ fontWeight: "bold", whiteSpace: "pre-wrap" }}>{card.text}</p>
            {!showAnswer ? (
              <button onClick={toggleAnswer} style={styles.button}>Reveal Mazal Outcome</button>
            ) : (
              <p style={{ color: "green", fontWeight: "bold" }}>
                {card.rewardType === "money" ? `You won $${card.reward}!` : `You gained ${card.reward} Zchut points!`}
              </p>
            )}
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 20 }}>
              <button onClick={() => onFinish(true, card.reward, card.rewardType)} style={styles.button}>Close</button>
              <button onClick={() => { setShowAnswer(false); onFinish(true, 0, "none"); }} style={styles.button}>Skip</button>
            </div>
          </>
        ) : (
          <>
            <p>Question {currentQ + 1} of {card.questions.length}</p>
            <div style={styles.questionBox}>
              <p style={{ fontWeight: "bold" }}>{card.questions[currentQ].question}</p>
              {showAnswer ? <p style={styles.answer}>{card.questions[currentQ].answer}</p> :
                <button onClick={toggleAnswer} style={styles.button}>Reveal Answer</button>
              }
            </div>

            <div style={{ marginTop: 10 }}>
              <button onClick={prevQuestion} disabled={currentQ === 0} style={styles.button}>Previous</button>
              <button onClick={nextQuestion} disabled={currentQ === card.questions.length - 1} style={{ ...styles.button, marginLeft: 10 }}>Next</button>
            </div>

            <div style={{ marginTop: 20 }}>
              {!accepted[currentQ] && showAnswer && <button onClick={acceptCorrect} style={styles.acceptButton}>Accept Correct (Add {card.questions[currentQ].points} Zchut)</button>}
              {accepted[currentQ] && <p style={{ color: "green", fontWeight: "bold" }}>Accepted Correct ✔</p>}
            </div>

            <div style={{ marginTop: 30 }}>
              <p>Total Zchut Points Earned: <strong>{totalPoints}</strong></p>
              {allCorrect ? <p style={{ color: "blue", fontWeight: "bold" }}>All questions answered correctly! You can proceed to the next card.</p> :
                <p>You can finish now with current points or continue answering.</p>
              }
            </div>

            <div style={{ display: "flex", justifyContent: "space-between", marginTop: 20 }}>
              <button onClick={() => onFinish(allCorrect, totalPoints, "zchut")} style={styles.button}>Finish Q&A</button>
              <button onClick={() => { onFinish(false, totalPoints, "zchut"); }} style={styles.button}>Finish Early</button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

// --- Build 44 board positions (11 per side) ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  // Top row (left -> right)
  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });

  // Right column (top -> bottom), skip corner
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });

  // Bottom row (right -> left), skip corner
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });

  // Left column (bottom -> top), skip corner
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Main App ---
function App() {
  const maxPlayers = 7;
  const availableColors = ["black", "purple", "blue", "brown", "orange", "red", "green"];
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [qaMode, setQaMode] = useState(false);
  const [currentCard, setCurrentCard] = useState(null);

  const [boardWidth, setBoardWidth] = useState(Math.min(window.innerWidth * 0.95, referenceSize));
  const boardRef = useRef(null);
  const [boardPositions, setBoardPositions] = useState(defaultBoardPositions);

  // --- Dice logic: roll two dice together ---
  const [diceRolls, setDiceRolls] = useState([]);
  const scale = boardWidth / referenceSize;

  useEffect(() => {
    const handleResize = () => setBoardWidth(Math.min(window.innerWidth * 0.95, referenceSize));
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;
    if (players.some(p => p.color === newPlayerColor)) { alert("Color taken!"); return; }
    setPlayers([...players, { name: newPlayerName, color: newPlayerColor, position: 0, zchutPoints: 1000, money: 2000, missTurn: false }]);
    setNewPlayerName(""); setNewPlayerColor("");
  };

  const startGame = () => {
    if (players.length < 2) { alert("At least 2 players required."); return; }
    setGameStarted(true);
  };

  const startQAFunc = (card) => { setCurrentCard(card); setQaMode(true); };
  const finishQAFunc = (allCorrect, points, rewardType = "zchut") => {
    setQaMode(false);
    const updatedPlayers = [...players];
    if (rewardType === "zchut") updatedPlayers[currentPlayerIndex].zchutPoints += points;
    else if (rewardType === "money") updatedPlayers[currentPlayerIndex].money += points;
    setPlayers(updatedPlayers);
    setCurrentCard(null);
  };

  // --- Movement animation with step-by-step ---
  const movePlayerBy = (steps) => {
    if (steps <= 0 || players.length === 0) return;
    const speedMs = 220;
    const updatedPlayers = [...players];
    const startIndex = updatedPlayers[currentPlayerIndex].position;
    const targetIndex = (startIndex + steps) % boardPositions.length;
    let stepCount = 0;

    const doStep = () => {
      stepCount++;
      updatedPlayers[currentPlayerIndex].position = (startIndex + stepCount) % boardPositions.length;
      setPlayers([...updatedPlayers]);

      if (stepCount < steps) setTimeout(doStep, speedMs);
      else {
        const landedIndex = updatedPlayers[currentPlayerIndex].position;
        // Example: Go to Jail on square 10 -> send to 30 and miss turn
        if (landedIndex === 10) {
          updatedPlayers[currentPlayerIndex].position = 30;
          updatedPlayers[currentPlayerIndex].missTurn = true;
          alert(`${updatedPlayers[currentPlayerIndex].name} goes to Jail and misses next turn!`);
          setPlayers([...updatedPlayers]);
        }
        // Trigger Q&A or other events here
      }
    };
    doStep();
  };

  // --- Roll both dice together ---
  const rollDice = (val) => {
    setDiceRolls((prev) => {
      const newRolls = [...prev, val];
      if (newRolls.length === 2) {
        const total = newRolls[0] + newRolls[1];
        movePlayerBy(total);
        return [];
      }
      return newRolls;
    });
  };

  const endTurn = () => {
    const updatedPlayers = [...players];
    // Reset missTurn if needed
    if (updatedPlayers[currentPlayerIndex].missTurn) {
      updatedPlayers[currentPlayerIndex].missTurn = false;
      alert(`${updatedPlayers[currentPlayerIndex].name} skips this turn!`);
    }
    setPlayers(updatedPlayers);
    setCurrentPlayerIndex((prev) => (players.length > 0 ? (prev + 1) % players.length : 0));
  };

  const boardNames = Array(boardPositions.length).fill("").map((_, i) => `Space ${i}`);

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      {!gameStarted ? (
        <>
          {players.length < maxPlayers && (
            <div style={styles.inputRow}>
              <input type="text" placeholder="Player Name" value={newPlayerName} onChange={(e) => setNewPlayerName(e.target.value)} style={styles.input} />
              <select value={newPlayerColor} onChange={(e) => setNewPlayerColor(e.target.value)} style={styles.input}>
                <option value="">Choose Color</option>
                {availableColors.filter(c => !players.some(p => p.color === c)).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <button onClick={addPlayer} style={styles.button}>Add Player</button>
            </div>
          )}
          <h2>Joined Players ({players.length}/{maxPlayers})</h2>
          <ul>
            {players.map((p, i) => (
              <li key={i} style={{ color: p.color, fontWeight: i === currentPlayerIndex ? "bold" : "normal" }}>{p.name} ({p.color})</li>
            ))}
          </ul>
          <button onClick={startGame} style={{ ...styles.button, marginTop: 20 }}>Start Game</button>
        </>
      ) : (
        <>
          <div style={{ marginBottom: 20 }}>
            <h2>Players</h2>
            <ul>
              {players.map((p, i) => (
                <li key={i} style={{ color: p.color, fontWeight: i === currentPlayerIndex ? "bold" : "normal" }}>
                  {p.name} - Position: {p.position}, Zchut: {p.zchutPoints}, Money: ${p.money} {i === currentPlayerIndex && "(Your Turn)"} {p.missTurn && "(Miss next turn)"}
                </li>
              ))}
            </ul>
          </div>

          {/* Game Board */}
          <div style={{ position: "relative", display: "inline-block", marginBottom: 20 }}>
            <img
              src={boardImage}
              alt="Game Board"
              style={{ width: boardWidth, maxWidth: "95vw", height: "auto", border: "2px solid #333", borderRadius: 12, display: "block" }}
            />

            {/* player tokens */}
            {players.map((player, idx) => {
              const pos = boardPositions[player.position % boardPositions.length];
              const left = Math.round(pos.x * scale - 12);
              const top = Math.round(pos.y * scale - 12);
              return (
                <div key={idx} title={`${player.name} - ${boardNames[player.position]}`} style={{
                  position: "absolute",
                  left,
                  top,
                  width: 24,
                  height: 24,
                  borderRadius: "50%",
                  backgroundColor: player.color,
                  border: idx === currentPlayerIndex ? "3px solid gold" : "1px solid #000",
                  display: "flex",
                  justifyContent: "center",
                  alignItems: "center",
                  fontSize: 12,
                  color: "#fff"
                }}>{idx + 1}</div>
              );
            })}

            {/* Card Buttons (example positions) */}
            <button onClick={() => startQAFunc(mazalCard)} style={{ position: "absolute", top: `20%`, left: `38%`, transform: "translate(-50%,-50%)", padding: "6px 12px", fontSize: 14, backgroundColor: "#28a745", color: "#fff", border: "2px solid #000", borderRadius: 6, cursor: "pointer" }}>Mazal Deck</button>

            <button onClick={() => startQAFunc(harHaBayitCard)} style={{ position: "absolute", top: `20%`, left: `62%`, transform: "translate(-50%,-50%)", padding: "6px 12px", fontSize: 14, backgroundColor: "#6f42c1", color: "#fff", border: "2px solid #000", borderRadius: 6, cursor: "pointer" }}>Har HaBayit Deck</button>

            <button onClick={() => startQAFunc(bereshitCard)} style={{ position: "absolute", top: `43%`, left: `54%`, transform: "translate(-50%,-50%)", padding: "6px 12px", fontSize: 14, backgroundColor: "#ffc107", color: "#000", border: "2px solid #333", borderRadius: 6, cursor: "pointer" }}>Tzadik Deck</button>
          </div>

          {/* Dice and Turn */}
          <div style={{ marginTop: 20 }}>
            <h2>Roll Dice</h2>
            <div style={{ display: "flex", justifyContent: "center", gap: 20 }}>
              <Dice sides={6} onRoll={rollDice} rollTime={1} />
              <Dice sides={6} onRoll={rollDice} rollTime={1} />
            </div>
            <button onClick={endTurn} style={{ ...styles.button, marginTop: 15 }}>End Turn</button>
          </div>
        </>
      )}

      {/* Q&A Modal */}
      {qaMode && currentCard && <CardQA card={currentCard} onFinish={finishQAFunc} />}
    </div>
  );
}

// --- Styles ---
const styles = {
  container: { fontFamily: "Arial, sans-serif", padding: 20, backgroundColor: "#f0f2f5", minHeight: "100vh", textAlign: "center" },
  button: { backgroundColor: "#007bff", color: "white", border: "none", borderRadius: 8, padding: "10px 20px", fontSize: 16, cursor: "pointer", margin: "5px" },
  input: { fontSize: 16, padding: "5px 10px", borderRadius: 4, border: "1px solid #ccc" },
  qaOverlay: { position: "fixed", left: 0, top: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.4)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 9999 },
  qaContainer: { fontFamily: "Arial, sans-serif", width: "min(700px, 95%)", margin: "20px auto", padding: 20, border: "2px solid #333", borderRadius: 12, backgroundColor: "#fff", textAlign: "left" },
  questionBox: { marginTop: 10, padding: 10, border: "1px solid #333", borderRadius: 6, backgroundColor: "#f9f9f9" },
  answer: { color: "green", fontWeight: "bold", marginTop: 10 },
  acceptButton: { backgroundColor: "#28a745", color: "#fff", border: "none", borderRadius: 6, padding: "8px 12px", cursor: "pointer", fontWeight: "bold" },
  inputRow: { display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 },
};

export default App;
